7139: 
7140:   // Running tests must not expect that some mouse boundary events are fired
7141:   // when something occurs in the parent process, e.g., when a popup is
7142:   // opened/closed at the last mouse cursor position in the parent process (the
7143:   // position may be different from the position which stored in this process).
7144:   // Therefore, let's ignore synthesized mouse events coming form another
7145:   // process if and only if they are not caused by the API.
7146:   if (aGUIEvent->CameFromAnotherProcess() && XRE_IsContentProcess() &&
7147:       !aGUIEvent->mFlags.mIsSynthesizedForTests) {
7148:     const PointerInfo* const lastMouseInfo =
7149:         PointerEventHandler::GetLastMouseInfo();
7150:     if (lastMouseInfo && lastMouseInfo->mIsSynthesizedForTests) {
7151:       switch (aGUIEvent->mMessage) {
7152:         // Synthesized eMouseMove will case mouse boundary events like
7153:         // mouseover, mouseout, and :hover state is changed at dispatching the
7154:         // events.
7155:         case eMouseMove:
7156:         // eMouseExitFromWidget comes from the parent process if the cursor
7157:         // crosses a puppet widget boundary.  Then, the event will be handled as
7158:         // a synthesized eMouseMove in this process and may cause unexpected
7159:         // `mouseout` and `mouseleave`.
7160:         case eMouseExitFromWidget:
7161:         // eMouseEnterIntoWidget causes updating the hover state under the event
7162:         // position which may be different from the last cursor position
7163:         // synthesized in this process.
7164:         case eMouseEnterIntoWidget:
7165:           if (!aGUIEvent->AsMouseEvent()->IsReal()) {
7166:             return NS_OK;
7167:           }
7168:           break;
7169:         default:
7170:           break;
7171:       }
7172:     }
7173:   }
7174: 
7175:   // Here we are granting some delays to ensure that user input events are
